import{_ as i,c as e,o as s,ah as l}from"./chunks/framework.Cnj7lwEt.js";const c=JSON.parse('{"title":"Руководство по использованию GitHub","description":"","frontmatter":{},"headers":[],"relativePath":"ru/github-guide.md","filePath":"ru/github-guide.md"}'),h={name:"ru/github-guide.md"};function t(r,a,n,d,o,p){return s(),e("div",null,a[0]||(a[0]=[l(`<h1 id="руководство-по-использованию-github" tabindex="-1">Руководство по использованию GitHub <a class="header-anchor" href="#руководство-по-использованию-github" aria-label="Permalink to “Руководство по использованию GitHub”">​</a></h1><h2 id="_01-1-введение" tabindex="-1">01.1- Введение <a class="header-anchor" href="#_01-1-введение" aria-label="Permalink to “01.1- Введение”">​</a></h2><p>GitHub - крупнейшая в мире платформа для хостинга кода, предоставляющая разработчикам мощное управление версиями, совместную разработку и управление проектами.</p><h2 id="_01-2-базовые-концепции" tabindex="-1">01.2- Базовые концепции <a class="header-anchor" href="#_01-2-базовые-концепции" aria-label="Permalink to “01.2- Базовые концепции”">​</a></h2><h3 id="_01-21-репозитории" tabindex="-1">01.21- Репозиторий <a class="header-anchor" href="#_01-21-репозитории" aria-label="Permalink to “01.21- Репозиторий”">​</a></h3><p>Репозиторий - это пространство для хранения проекта, содержащее все файлы, папки и историю изменений каждого файла.</p><h3 id="_01-22-ветка" tabindex="-1">01.22- Ветка <a class="header-anchor" href="#_01-22-ветка" aria-label="Permalink to “01.22- Ветка”">​</a></h3><p>Ветка позволяет разрабатывать новые функции или исправлять ошибки без влияния на основную ветку.</p><h3 id="_01-23-коммит" tabindex="-1">01.23- Коммит <a class="header-anchor" href="#_01-23-коммит" aria-label="Permalink to “01.23- Коммит”">​</a></h3><p>Коммит - это запись изменений файла, для каждого коммита создается уникальный идентификатор.</p><h3 id="_01-24-pull-request" tabindex="-1">01.24- Pull Request <a class="header-anchor" href="#_01-24-pull-request" aria-label="Permalink to “01.24- Pull Request”">​</a></h3><p>Pull Request - это запрос на слияние изменений в основную ветку, облегчающий проверку кода и обсуждение.</p><h2 id="_01-3-быстрыи-старт" tabindex="-1">01.3- Быстрый старт <a class="header-anchor" href="#_01-3-быстрыи-старт" aria-label="Permalink to “01.3- Быстрый старт”">​</a></h2><h3 id="_01-31-создание-аккаунта" tabindex="-1">01.31- Создание аккаунта <a class="header-anchor" href="#_01-31-создание-аккаунта" aria-label="Permalink to “01.31- Создание аккаунта”">​</a></h3><p>Посетите <a href="https://github.com" target="_blank" rel="noreferrer">официальный сайт GitHub</a> для регистрации.</p><h3 id="_01-32-создание-репозитория" tabindex="-1">01.32- Создание репозитория <a class="header-anchor" href="#_01-32-создание-репозитория" aria-label="Permalink to “01.32- Создание репозитория”">​</a></h3><ol><li>Нажмите кнопку &quot;+&quot; вверху</li><li>Выберите &quot;New repository&quot;</li><li>Введите имя репозитория и описание</li><li>Выберите публичный или приватный</li><li>Нажмите &quot;Create repository&quot;</li></ol><h3 id="_01-33-клонирование-репозитория" tabindex="-1">01.33- Клонирование репозитория <a class="header-anchor" href="#_01-33-клонирование-репозитория" aria-label="Permalink to “01.33- Клонирование репозитория”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/username/repository.git</span></span></code></pre></div><h3 id="_01-34-создание-ветки" tabindex="-1">01.34- Создание ветки <a class="header-anchor" href="#_01-34-создание-ветки" aria-label="Permalink to “01.34- Создание ветки”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-35-коммит-изменении" tabindex="-1">01.35- Коммит изменений <a class="header-anchor" href="#_01-35-коммит-изменении" aria-label="Permalink to “01.35- Коммит изменений”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Добавить новую функцию&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-36-создание-pull-request" tabindex="-1">01.36- Создание Pull Request <a class="header-anchor" href="#_01-36-создание-pull-request" aria-label="Permalink to “01.36- Создание Pull Request”">​</a></h3><p>Создайте Pull Request на странице GitHub и дождитесь проверки и слияния.</p><h2 id="_01-4-общие-операции" tabindex="-1">01.4- Общие операции <a class="header-anchor" href="#_01-4-общие-операции" aria-label="Permalink to “01.4- Общие операции”">​</a></h2><h3 id="_01-41-форк" tabindex="-1">01.41- Форк <a class="header-anchor" href="#_01-41-форк" aria-label="Permalink to “01.41- Форк”">​</a></h3><p>Используйте форк для копирования проекта другого человека в свой аккаунт и его модификации.</p><h3 id="_01-42-звезда" tabindex="-1">01.42- Звезда <a class="header-anchor" href="#_01-42-звезда" aria-label="Permalink to “01.42- Звезда”">​</a></h3><p>Звезда указывает на то, что вам нравится проект, и вы можете легко найти его позже.</p><h3 id="_01-43-наблюдение" tabindex="-1">01.43- Наблюдение <a class="header-anchor" href="#_01-43-наблюдение" aria-label="Permalink to “01.43- Наблюдение”">​</a></h3><p>Используйте наблюдение для получения уведомлений об обновлениях проекта.</p><h3 id="_01-44-проблема" tabindex="-1">01.44- Проблема <a class="header-anchor" href="#_01-44-проблема" aria-label="Permalink to “01.44- Проблема”">​</a></h3><p>Проблемы используются для сообщения об ошибках, запроса функций или обсуждения идей.</p><h2 id="_01-5-лучшие-практики" tabindex="-1">01.5- Лучшие практики <a class="header-anchor" href="#_01-5-лучшие-практики" aria-label="Permalink to “01.5- Лучшие практики”">​</a></h2><ol><li><strong>Четкие сообщения коммитов</strong> - сообщайте другим цель каждого коммита</li><li><strong>Использование веток</strong> - не разрабатывайте напрямую на основной ветке</li><li><strong>Регулярная синхронизация</strong> - синхронизируйте локальный репозиторий с удаленным</li><li><strong>Проверка кода</strong> - проводите проверки кода через Pull Request</li><li><strong>Документирование проекта</strong> - добавляйте README и необходимую документацию к проекту</li></ol><h2 id="_01-6-связанные-ресурсы" tabindex="-1">01.6- Связанные ресурсы <a class="header-anchor" href="#_01-6-связанные-ресурсы" aria-label="Permalink to “01.6- Связанные ресурсы”">​</a></h2><ul><li><a href="https://docs.github.com" target="_blank" rel="noreferrer">Официальная документация GitHub</a></li><li><a href="/ru/91git.html">Базовое руководство по Git</a></li><li><a href="/ru/全部资源概述.html">Обзор всех ресурсов</a></li></ul>`,38)]))}const b=i(h,[["render",t]]);export{c as __pageData,b as default};
